exercises.solution_code:
#include <iostream>
#include <string>

class Item {
    std::string m_name{ "unknown" };
    int m_qty{ 0 };
public:
    Item() = default;
    Item(const std::string& name, int qty = 1) : m_name{ name }, m_qty{ qty } {}

    const std::string& getName() const { return m_name; }
    int getQty() const { return m_qty; }
};

int main() {
    int n{};
    std::cin >> n;
    std::cin.ignore();

    for (int i = 0; i < n; ++i) {
        std::string line;
        std::getline(std::cin, line);

        Item item{};

        if (line == "DEFAULT") {
            item = Item{};
        } else {
            auto spacePos = line.find(' ');
            if (spacePos != std::string::npos) {
                std::string name = line.substr(0, spacePos);
                int qty = std::stoi(line.substr(spacePos + 1));
                item = Item{ name, qty };
            } else {
                item = Item{ line };
            }
        }

        std::cout << item.getName() << ": " << item.getQty() << "\n";
    }

    return 0;
}

