#include <iostream>
#include <iomanip>
#include <string>
#include <sstream>

class TempReading {
    int m_sensorId;
    double m_celsius;
public:
    TempReading(int sensorId = 0, double celsius = 20.0)
        : m_sensorId{ sensorId }, m_celsius{ celsius } {}

    int    getSensorId() const { return m_sensorId; }
    double getCelsius()  const { return m_celsius; }
};

int main() {
    int n{};
    std::cin >> n;
    std::cin.ignore();

    std::cout << std::fixed << std::setprecision(1);

    for (int i = 0; i < n; ++i) {
        std::string line;
        std::getline(std::cin, line);

        TempReading reading{};

        if (line == "DEFAULT") {
            reading = TempReading{};
        } else {
            std::istringstream iss{line};
            int sid{};
            iss >> sid;
            double temp{};
            if (iss >> temp) {
                reading = TempReading{sid, temp};
            } else {
                reading = TempReading{sid};
            }
        }

        std::cout << "Sensor " << reading.getSensorId() << ": "
                  << reading.getCelsius() << " C\n";
    }

    return 0;
}
